import java.util.Arrays;

public int minimumEnergy(int[][] tasks) {
    Arrays.sort(tasks, (a, b) -> (b[1] - b[0]) - (a[1] - a[0]));

    int energy = 0;
    for (int[] task : tasks) {
        energy = Math.max(energy + task[0], task[1]);
    }
    return energy;
}
```

